        sig = inspect.signature(notify.finish)
        params = list(sig.parameters.keys())
        # Should have 'message' parameter (besides 'self')
        self.assertIn('message', params,
                      "QueryNotifyPrint.finish should accept a 'message' parameter")

    def test_query_notify_print_finish_has_non_none_default(self):
        """Test that QueryNotifyPrint.finish has a non-None default message"""
        try:
            from sherlock.notify import QueryNotifyPrint
        except ImportError:
            try:
                from notify import QueryNotifyPrint
            except ImportError as e:
                self.fail(f"Could not import QueryNotifyPrint: {e}")

        import inspect
        try:
            notify = QueryNotifyPrint()
        except Exception:
            notify = QueryNotifyPrint(result=None)

        sig = inspect.signature(notify.finish)
        params = sig.parameters

        if 'message' in params:
            default = params['message'].default
            # In the fixed version, the default should be a meaningful string
            # not None (the buggy base class has None, but QueryNotifyPrint should override)
            # The fix adds a finish method with message="The processing has been finished."
            self.assertIsNotNone(default,
                                 "QueryNotifyPrint.finish 'message' default should not be None")
            self.assertIsInstance(default, str,
                                  "QueryNotifyPrint.finish 'message' default should be a string")


