    def test_check_for_parameter_and_multiple_usernames_integration(self):
        """Test that CheckForParameter and MultipleUsernames work together correctly"""
        try:
            from sherlock.sherlock import CheckForParameter, MultipleUsernames
        except ImportError:
            from sherlock import CheckForParameter, MultipleUsernames

        username = "john{?}doe"

        # Should detect the parameter
        self.assertTrue(CheckForParameter(username))

        # Should generate multiple usernames
        variants = MultipleUsernames(username)

        # All expected variants should be present
        expected = ["john_doe", "john-doe", "john.doe"]
        for expected_username in expected:
            self.assertIn(expected_username, variants,
                          f"Expected '{expected_username}' in MultipleUsernames output")

    def test_regular_username_without_placeholder(self):
        """Test that regular usernames without {?} are handled correctly"""
        try:
            from sherlock.sherlock import CheckForParameter
        except ImportError:
            from sherlock import CheckForParameter

        regular_usernames = ["johndoe", "john_doe", "john-doe", "john.doe"]
        for username in regular_usernames:
            self.assertFalse(CheckForParameter(username),
                             f"CheckForParameter should return False for '{username}'")


